import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"财富","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/wealth.md","filePath":"zh-CN/portfolio-and-statements/wealth.md"}'),o={name:"portfolio-and-statements/wealth.md"};function l(i,t,h,n,s,p){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="财富" tabindex="-1">财富 <a class="header-anchor" href="#财富" aria-label="Permalink to &quot;财富&quot;">​</a></h1><p>财富页是长桥的理财产品聚合入口，集中展示基金、结构化产品等多类理财产品，方便用户一站式浏览和购买。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>底部导航「市场」→ 顶部切换「财富」标签。</p><h2 id="账户信息" tabindex="-1">账户信息 <a class="header-anchor" href="#账户信息" aria-label="Permalink to &quot;账户信息&quot;">​</a></h2><p>页面顶部显示当前账户的财富资产总览，包含账户类型和以折算货币计价的财富总资产。</p><h2 id="快捷入口" tabindex="-1">快捷入口 <a class="header-anchor" href="#快捷入口" aria-label="Permalink to &quot;快捷入口&quot;">​</a></h2><p>提供 8 个理财品类的快捷入口：</p><p><strong>第一行：</strong> 公募基金 / 闲钱理财 / 余额通 / 基金定投</p><p><strong>第二行：</strong> 结构化产品 / 私募基金 / 债券 / 更多</p><p>点击对应入口直接跳转到该类产品的列表页。</p><h2 id="闲钱理财" tabindex="-1">闲钱理财 <a class="header-anchor" href="#闲钱理财" aria-label="Permalink to &quot;闲钱理财&quot;">​</a></h2><p>展示适合短期低风险理财的基金产品列表，每条产品包含以下信息：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>基金名称</td><td>产品完整名称</td></tr><tr><td>计价货币</td><td>如 HKD、USD 等</td></tr><tr><td>基金类型</td><td>如债券型、股票型</td></tr><tr><td>风险等级</td><td>如中低风险、中高风险</td></tr><tr><td>近一年收益</td><td>近一年的历史收益率（仅供参考，不代表未来收益）</td></tr><tr><td>基金规模</td><td>产品的资产管理规模</td></tr><tr><td>产品亮点</td><td>产品特色标签，如成立年限、历史表现标注等</td></tr></tbody></table><p>点击「买入」可进入购买流程。</p><blockquote><p>基金投资存在风险，历史收益不代表未来表现，请根据自身风险承受能力谨慎投资。</p></blockquote><h2 id="结构化产品" tabindex="-1">结构化产品 <a class="header-anchor" href="#结构化产品" aria-label="Permalink to &quot;结构化产品&quot;">​</a></h2><p>展示票据类结构化产品，支持按类型筛选：</p><ul><li><strong>全部类型</strong></li><li><strong>固定票息票据（FCN）</strong></li><li><strong>逐步递减自动敲出票据</strong></li></ul><p>每条产品展示产品名称、计价货币、产品类型和挂钩标的股票。</p><blockquote><p>结构化产品风险较高，请在充分了解产品条款后再做决策。详情请参考<a href="/wiki/funds-and-wealth/结构化产品">结构化产品</a>。</p></blockquote><h2 id="可执行操作" tabindex="-1">可执行操作 <a class="header-anchor" href="#可执行操作" aria-label="Permalink to &quot;可执行操作&quot;">​</a></h2><ul><li>点击快捷入口 → 进入对应类别产品列表</li><li>点击产品「买入」按钮 → 发起购买流程</li><li>切换结构化产品类型标签 → 筛选显示</li><li>点击 Banner → 查看推广产品详情</li></ul><h2 id="更多功能" tabindex="-1">更多功能 <a class="header-anchor" href="#更多功能" aria-label="Permalink to &quot;更多功能&quot;">​</a></h2><p>点击快捷入口「更多」进入全功能列表，展示财富页所有可用工具入口。</p><h3 id="首页快捷入口管理" tabindex="-1">首页快捷入口管理 <a class="header-anchor" href="#首页快捷入口管理" aria-label="Permalink to &quot;首页快捷入口管理&quot;">​</a></h3><p>支持自定义首页快捷入口（最多 7 个）。在「更多」页面顶部可拖拽排序或勾选/取消各入口的显示状态。</p><h3 id="全部功能入口" tabindex="-1">全部功能入口 <a class="header-anchor" href="#全部功能入口" aria-label="Permalink to &quot;全部功能入口&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入口</th><th>说明</th></tr></thead><tbody><tr><td>公募基金</td><td>展示基金排行榜，含名称、最新净值、近 1 年收益等信息</td></tr><tr><td>闲钱理财</td><td>分为「余额通 T 日灵活申赎」和「进阶理财」两大板块，后者展示债券型等中低风险基金</td></tr><tr><td>余额通</td><td>余额通增值计划入口，支持港元、美元货币基金申请，提供模拟收益计算器</td></tr><tr><td>基金定投</td><td>设置周期性自动买入计划，详见<a href="/wiki/funds-and-wealth/基金/基金定投">基金定投</a></td></tr><tr><td>结构化产品</td><td>票据类结构化产品列表，包含固定票息票据（FCN）等类型</td></tr><tr><td>私募基金</td><td>需通过专业投资者（PI）认证后方可查看，点击后提示「去认证」</td></tr><tr><td>债券</td><td>美债等债券投资入口</td></tr><tr><td>基金课堂</td><td>提供基金相关学习内容，涵盖基金入门、资产配置、结构化产品等系列课程</td></tr><tr><td>PI 专区</td><td>专业投资者专属入口，提供专属客服、国际配售、私募基金、债券直投等特权</td></tr><tr><td>基金订单</td><td>查看基金持仓、交易记录、基金盈亏及定投计划</td></tr></tbody></table><h3 id="专业投资者-pi-认证" tabindex="-1">专业投资者（PI）认证 <a class="header-anchor" href="#专业投资者-pi-认证" aria-label="Permalink to &quot;专业投资者（PI）认证&quot;">​</a></h3><p>私募基金、PI 专区等功能需完成专业投资者认证后方可使用。认证方式：</p><ul><li><strong>方法一</strong>：在长桥账户持有等值 800 万港元以上资产，系统自动识别</li><li><strong>方法二</strong>：上传持有等值 800 万港元以上资产的证明文件</li></ul><p>认证流程：发起认证声明 → 提交资料审核 → 审核通过。</p><blockquote><p>被认证为专业投资者后，长桥可豁免履行若干监管要求（如提供身份资料、确认交易要点等）。您可随时撤回专业投资者身份，并有权在决策前寻求第三方独立意见。</p></blockquote>',34)])])}const b=a(o,[["render",l]]);export{c as __pageData,b as default};
